import{C as e,o as n,c as l,a5 as a,E as h}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"5. Validator status (voting, delinquent, healthy)","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/5-validator-status.md","filePath":"module-1/5-validator-status.md","lastUpdated":1780937944000}'),o={name:"module-1/5-validator-status.md"},c=Object.assign(o,{setup(r){const t={id:"m1-5-validator-status",title:"🧠 Mini-check: Validator status",intro:"3 питання — як читати validator health.",questions:[{type:"diagnose",q:'Solana validators виводить твоїй validator у "Delinquent Stake" sекції. Що з цього вірно (обери всі)?',options:["Twi validator не голосував >128 slots на rooted slot — це Solana definition of delinquent","Inший validator може бути delinquent тимчасово через network issue, recoverable","Delinquent validator втрачає stake rewards для періоду delinquency","Cluster автоматично slashes delinquent validators"],correct:[0,1,2],explanation:"#1, #2, #3 правильні. #4 НЕПРАВИЛЬНО: Solana НЕ slashing для delinquency (на цей момент). Ти просто не заробляєш rewards поки delinquent."},{type:"command",q:"Як отримати JSON з усіма validators і їх vote credits? Напиши команду.",accepts:["solana validators --output json","solana validators --output json-compact","sudo /home/solana/ag/bin/solana validators --output json","solana validators --output json --url mainnet-beta"],ideal:"solana validators --output json",explanation:"--output json дає structured data для parsing (через jq, python, etc). За дефолтом вивід table format. --output json-compact = without newlines (smaller)."},{type:"explain",q:'Поясни різницю між "Active Stake" і "Delinquent Stake" у cluster. Чому ці метрики matter для health всього cluster?',ideal:`Active Stake = total SOL яка staked до validators які зараз правильно голосують (non-delinquent). Delinquent Stake = SOL staked до validators які НЕ голосують зараз (delinquent).

Чому matter:
1. Consensus needs > 2/3 stake voting щоб produce finality. Якщо Active Stake падає нижче 67% — cluster haltиться (no finality можлива).
2. Якщо delinquent stake велика — cluster під risk. Mainnet target: delinquent < 5-10%.
3. На Alpenglow halt threshold ~18% delinquent — beyond cluster stops producing blocks.

Як твій restart це впливає: коли ти restartиш свій validator, він тимчасово стає delinquent (поки catches up). Якщо cluster delinquent вже high — твій restart може pushнути кластер ближче до halt threshold. Тому з §4 cheatsheet pre-flight check: "якщо delinquent > 5%, не restartй".`,explanation:"Ключове: active needed for finality (2/3 threshold), delinquent зростає коли validators відстають, restart твоєю додає до delinquent тимчасово. Якщо описала обидва + halt threshold — повна відповідь."}]};return(p,s)=>{const i=e("Quiz");return n(),l("div",null,[s[0]||(s[0]=a("",69)),h(i,{data:t}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
